import React from 'react';

interface Technician {
    id: string;
    name: string;
    email: string;
}

const mockTechnicians: Technician[] = [
    { id: '1', name: 'Técnico 1', email: 'tec1@provedor.com' },
    { id: '2', name: 'Técnico 2', email: 'tec2@provedor.com' },
];

const Technicians: React.FC = () => {
    return (
        <div style={{ padding: '1rem' }}>
            <h1>Técnicos</h1>
            <p>Lista simples de técnicos. Depois vamos ligar com o backend e criar formulários completos.</p>
            <ul>
                {mockTechnicians.map((t) => (
                    <li key={t.id}>
                        <strong>{t.name}</strong> - {t.email}
                    </li>
                ))}
            </ul>
        </div>
    );
};

export default Technicians;
